TDD CYCLE
BEGIN
 // RED: Write failing test first
 WRITE_TEST(describe new feature)

 // GREEN: Write minimal code to pass test
 WRITE_CODE(pass the test)

 // REFACTOR: Improve code without breaking tests
 REFACTOR_CODE(improve readability)

 // Benefits:
 // - Defects caught immediately (low cost)
 // - Tests serve as documentation
 // - Safe to refactor (tests catch regressions)
 // - Reduces technical debt
END
